use serde::{Serialize, Deserialize};

/// Settlement action type — maps to on-chain TaskStatus variants.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
#[serde(rename_all = "snake_case")]
pub enum EventType {
    /// Normal task settlement (on-chain: settle_task instruction)
    Settle,
    /// Refund a previously settled task (on-chain: refund_task instruction)
    Refund,
}

/// Event published to the cto:settlements Redis stream.
/// Contains all data needed for the sidecar to submit a Solana transaction.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SettlementEvent {
    /// Unique task identifier (becomes PDA seed via SHA-256 hash on-chain)
    pub task_id: String,
    /// Customer's Solana wallet pubkey (base58-encoded)
    pub customer_pubkey: String,
    /// Billable amount in USDC lamports (1 USDC = 1_000_000 lamports for 6 decimals)
    pub amount_usdc_lamports: u64,
    /// SHA-256 hash of the receipt JSON (written on-chain for verifiability)
    pub receipt_hash: [u8; 32],
    /// S3 URL where the full receipt JSON is stored
    pub receipt_url: String,
    /// If a public agent marketplace package was used
    pub agent_package_id: Option<String>,
    /// Whether quality attestations (Tess/Cipher/Stitch) passed
    pub quality_met: bool,
    /// Settlement action type
    pub event_type: EventType,
    /// Name of the CodeRun CR that triggered this event
    pub coderun_name: String,
    /// Unix timestamp (seconds) when the event was created
    pub timestamp: i64,
}
