use serde::{Serialize, Deserialize};
use sha2::{Sha256, Digest};
use crate::billing::config::SolanaBillingConfig;
use crate::billing::BillingError;

/// Tier-based billing rates in USDC lamports (1 USDC = 1_000_000 lamports).
const STANDARD_RATE: u64 = 750_000;  // $0.75 per run
const HIGH_MEM_RATE: u64 = 1_500_000; // $1.50 per run
const GPU_RATE: u64 = 3_000_000;      // $3.00 per run

/// A single line item in the receipt's cost breakdown.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CostLineItem {
    pub description: String,
    pub amount_usdc: f64,
}

/// Complete receipt JSON uploaded to S3.
/// The SHA-256 hash of this struct's canonical JSON serialization
/// is stored on-chain in TaskReceipt.receipt_hash.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReceiptJson {
    pub task_id: String,
    pub customer: String,
    pub coderun_name: String,
    pub duration_seconds: u64,
    pub infra_tier: String,
    pub provider: String,
    pub agent_used: String,
    pub itemized_costs: Vec<CostLineItem>,
    pub total_usdc: f64,
    pub timestamp: String, // ISO 8601
}

impl ReceiptJson {
    /// Serialize to canonical JSON bytes for deterministic hashing.
    pub fn to_json_bytes(&self) -> serde_json::Result<Vec<u8>>;

    /// Compute SHA-256 hash of the canonical JSON representation.
    /// This hash is stored on-chain and can be used to verify receipt integrity.
    pub fn compute_sha256(&self) -> [u8; 32];
}

/// Upload receipt JSON to S3 and return (url, sha256_hash).
/// S3 key format: {config.receipt_s3_prefix}/{task_id}/{timestamp}.json
pub async fn upload_receipt(
    receipt: &ReceiptJson,
    config: &SolanaBillingConfig,
) -> Result<(String, [u8; 32]), BillingError>;

/// Compute billable amount in USDC lamports from infra tier.
/// This is a flat per-run rate (not duration-based for hackathon simplicity).
/// Tier rates: standard=$0.75, high-mem=$1.50, GPU=$3.00.
pub fn compute_billing_amount(duration_seconds: u64, tier: &str) -> u64;
```

