use std::sync::Arc;
use crate::billing::event::SettlementEvent;
use crate::billing::BillingError;

/// Publishes settlement events to the cto:settlements Redis stream.
/// Thread-safe and designed to be shared via Arc across async tasks.
pub struct SettlementPublisher {
    client: redis::Client,
}

impl SettlementPublisher {
    /// Create a new publisher connected to the given Redis URL.
    /// Does not establish a connection immediately — connections are lazy.
    pub fn new(redis_url: &str) -> Result<Self, BillingError>;

    /// Publish a settlement event to the cto:settlements stream via XADD.
    /// Returns the Redis stream entry ID (e.g., "1234567890-0").
    ///
    /// The XADD includes both the full JSON payload and indexed fields:
    /// - "event": full SettlementEvent JSON
    /// - "task_id": event.task_id
    /// - "event_type": "settle" or "refund"
    pub async fn publish(&self, event: &SettlementEvent) -> Result<String, BillingError>;

    /// Fire-and-forget publish — spawns a tokio task.
    /// Logs errors but never blocks or propagates failures.
    pub fn publish_fire_and_forget(self: Arc<Self>, event: SettlementEvent);
}
